mapper.select:
SELECT count(DISTINCT p.id) FROM products p
LEFT JOIN categories c ON p.category_id = c.id

    p."stateId" = 'PUBLISHED'
    AND (c.id = #{categoryId} OR c.parent_id = #{categoryId})
    AND p.brand = #{brand}
    AND (p.name LIKE #{q} OR p.description LIKE #{q} OR p.brand LIKE #{q})
    AND EXISTS (
        SELECT 1 FROM offers o
        WHERE o.product_id = p.id AND o."stateId" = 'ACTIVE' AND o.selling_price >= #{minPrice}
    )
    AND EXISTS (
        SELECT 1 FROM offers o
        WHERE o.product_id = p.id AND o."stateId" = 'ACTIVE' AND o.selling_price <= #{maxPrice}
    )

SELECT p.id as "productId", p.name as "name", p.short_description as "shortDescription", p.brand as "brand", p.slug as "slug", c.name as "categoryName", c.slug as "categorySlug", pm_img.cdn_url as "imageUrl", pm_img.thumbnail_url as "thumbnailUrl", MIN(o.selling_price) as "minPrice", MAX(o.selling_price) as "maxPrice", COALESCE(SUM(inv.available_quantity), 0) as "totalStock", CASE WHEN COALESCE(SUM(inv.available_quantity), 0) > 0 THEN true ELSE false END as "inStock", COUNT(DISTINCT r.id) as "reviewCount", COALESCE(AVG(r.rating), 0) as "avgRating" FROM products p LEFT JOIN categories c ON p.category_id = c.id LEFT JOIN ( SELECT pm.product_id, ma.cdn_url, ma.thumbnail_url FROM product_media pm JOIN media_assets ma ON ma.id = pm.asset_id WHERE pm.is_primary = true ) pm_img ON pm_img.product_id = p.id LEFT JOIN product_variants pv ON pv.product_id = p.id LEFT JOIN offers o ON o.product_id = p.id AND o."stateId" = 'ACTIVE' LEFT JOIN inventory_item inv ON inv.variant_id = pv.id LEFT JOIN product_reviews r ON r.product_id = p.id AND r.state_id = 'APPROVED'
p."stateId" = 'PUBLISHED' AND (c.id = #{categoryId} OR c.parent_id = #{categoryId}) AND p.brand = #{brand} AND (p.name LIKE #{q} OR p.description LIKE #{q} OR p.brand LIKE #{q})
GROUP BY p.id, p.name, p.short_description, p.brand, p.slug, c.name, c.slug, pm_img.cdn_url, pm_img.thumbnail_url HAVING MIN(o.selling_price) >= #{minPrice} HAVING MAX(o.selling_price) <= #{maxPrice} ${orderby} ${pagination}
